// 安全地获取输入数据
const input = Array.isArray(items) ? items.map(it => it?.json ?? it) : [];

// 数据转换函数
const transformData = (input) => {
  return input.map(item => {
    // 提取QRCODE中的参数并构建uuid
    const qrcode = item?.data?.["QRCODE"];
    let uuid = null;

    if (typeof qrcode === 'string' && qrcode.includes('?')) {
      const urlPart = qrcode.split('?')[1] ?? '';

      // 正则用于提取 a 的末尾十六进制部分，以及 b、c
      const match = urlPart.match(/a=([\w]+?)([A-F0-9]+)&b=([A-F0-9]+)&c=([A-F0-9]+)/i)
        || urlPart.match(/a=[\w\s]+?([A-F0-9]+)&b=([A-F0-9]+)&c=([A-F0-9]+)/i);

      if (match && match.length === 4) {
        uuid = (match[1] + match[2] + match[3]).toUpperCase();
      }
    }

    // remark 的来源：优先使用数据中的 "reamrk"，若没有再尝试 "remark"，都没有则为 null
    const remarkFromInput = item?.data?.["reamrk"] ?? item?.data?.["remark"] ?? null;

    // 构建输出对象
    return {
      "retroid": item.retroid,
      "machine_type": item.data?.["TestStation"] ?? null,
      "job_number": item.job_number ?? null,
      "uuid": uuid,
      "phase": item.data?.["phase"] ?? null,
      "wifi_mac": item.data?.["Bluetooth MAC"] ?? null,
      "battery": item.data?.["BatteryPackLot"] ?? null,
      "screen": null,
      "remark": remarkFromInput,
      "createtime": item.createtime ?? null
    };
  });
};

// 执行转换并返回结果
const output = transformData(input);

// 返回处理后的数据
return output.map(data => ({ json: data }));

// 1) 当前 Code 节点的入参（上一节点传进来的）
const inputItems = $input.all();  // [{ json: {...} }, ...]

// 2) 另一个节点的数据（用节点名引用）
const prodItems = $('插入到production_detail2').all(); // [{ json: {...} }, ...]

// 建 retroid -> 入参json 映射
const inputByRetroid = new Map(
  inputItems.map(i => [i.json.retroid, i.json])
);

// 合并：以 production_detail2 为主
const out = prodItems.map(p => {
  const pjson = p.json;
  const injson = inputByRetroid.get(pjson.retroid);

  return {
    json: {
      ...pjson,
      pack_id: injson ? Number(injson.id) : null,  // 入参id -> pack_id
    }
  };
});

return out;
